import re
from collections import Counter

biz_data = var_functions.query_db:16

print('Total businesses accepting credit cards: ' + str(len(biz_data)))
print('Sample description: ' + str(biz_data[0]['description'])[:200])

# Simple category extraction from descriptions
category_count = Counter()
business_categories = {}

for biz in biz_data:
    desc = biz.get('description', '')
    if not desc:
        continue

    # Clean description - remove location part
    desc_clean = desc.split(', this')[1] if ', this' in desc else desc

    # Find categories - look for after keywords like "in" or "including"
    if 'services in' in desc:
        # Find text after "services in" until period
        start = desc.find('services in') + 12
        end = desc.find('.', start)
        if end > start:
            cat_text = desc[start:end]
            cats = re.split(r',\s*|\s+and\s+', cat_text)
            for cat in cats:
                cat_clean = cat.strip()
                if cat_clean and cat_clean != '':
                    category_count[cat_clean] += 1
                    if biz['business_id'] not in business_categories:
                        business_categories[biz['business_id']] = []
                    business_categories[biz['business_id']].append(cat_clean)
    elif 'including' in desc:
        # Find text after "including" until period
        start = desc.find('including') + 10
        end = desc.find('.', start)
        if end > start:
            cat_text = desc[start:end]
            cats = re.split(r',\s*|\s+and\s+', cat_text)
            for cat in cats:
                cat_clean = cat.strip()
                if cat_clean and cat_clean != '':
                    category_count[cat_clean] += 1
                    if biz['business_id'] not in business_categories:
                        business_categories[biz['business_id']] = []
                    business_categories[biz['business_id']].append(cat_clean)

print('Unique categories found: ' + str(len(category_count)))
print('Top categories:')
for cat, count in category_count.most_common(15):
    print('  ' + cat + ': ' + str(count))

