import json, re
from collections import Counter

# Load businesses and reviews
biz = var_functions.query_db:76
rev = var_functions.query_db:64

# Filter credit card businesses
credit_biz = []
for b in biz:
    attrs = b.get('attributes')
    if isinstance(attrs, dict) and attrs.get('BusinessAcceptsCreditCards') == 'True':
        credit_biz.append(b)

# Extract categories
cat_counts = Counter()
biz_cats = {}

for b in credit_biz:
    desc = b.get('description', '')
    bid = b.get('business_id', '')

    cat_text = ''
    if 'services in' in desc.lower():
        m = re.search(r'services in ([^\.]+)', desc, re.IGNORECASE)
        if m: cat_text = m.group(1)
    elif 'including' in desc.lower():
        m = re.search(r'including ([^\.]+)', desc, re.IGNORECASE)
        if m: cat_text = m.group(1)
    elif 'fields of' in desc.lower():
        m = re.search(r'fields of ([^\.]+)', desc, re.IGNORECASE)
        if m: cat_text = m.group(1)

    if cat_text:
        if cat_text.endswith('.'): cat_text = cat_text[:-1]
        cats = [c.strip().rstrip('.,') for c in re.split(r',\s+|\sand\s', cat_text) if c.strip()]
        biz_cats[bid] = cats
        for c in cats:
            if len(c) > 1:
                cat_counts[c] += 1

if not cat_counts:
    result = {'error': 'No categories found'}
else:
    top_cat, top_cnt = cat_counts.most_common(1)[0]

    top_bids = []
    for bid, cats in biz_cats.items():
        if top_cat in cats:
            top_bids.append(bid)

    rev_ids = [bid.replace('businessid_', 'businessref_') for bid in top_bids]

    total_rating = 0.0
    rating_cnt = 0

    for r in rev:
        if r.get('business_ref') in rev_ids:
            total_rating += float(r.get('avg_rating', 0))
            rating_cnt += 1

    avg_rating = round(total_rating / rating_cnt, 2) if rating_cnt > 0 else 0

    result = {
        'top_category': top_cat,
        'business_count': top_cnt,
        'avg_rating': avg_rating
    }

print('__RESULT__:')
print(result)

