print(f"Review summaries: {len(rev)}")

# Simple category extraction manually
all_categories = []
cat_count = Counter()

for b in biz:
    desc = b.get('description','')
    bid = b.get('business_id','')

    # Find categories (simple string search)
    cats = []

    # Look for pattern "services in ..." or "including ..." or "fields of ..."
    if desc.find('services in ') > 0:
        start = desc.find('services in ') + len('services in ')
        end = desc.find('.', start)
        if end > start:
            cat_text = desc[start:end]
            parts = cat_text.split(',')
            cats = [p.strip() for p in parts if p.strip()]
            # Remove "and" from last category
            if cats:
                last_cat = cats[-1]
                if last_cat.startswith('and '):
                    cats[-1] = last_cat[4:]
    elif desc.find('including ') > 0:
        start = desc.find('including ') + len('including ')
        end = desc.find('.', start)
        if end > start:
            cat_text = desc[start:end]
            parts = cat_text.split(',')
            cats = [p.strip() for p in parts if p.strip()]
            if cats:
                last_cat = cats[-1]
                if last_cat.startswith('and '):
                    cats[-1] = last_cat[4:]
    elif desc.find('fields of ') > 0:
        start = desc.find('fields of ') + len('fields of ')
        end = desc.find('.', start)
        if end > start:
            cat_text = desc[start:end]
            parts = cat_text.split(',')
            cats = [p.strip() for p in parts if p.strip()]
            if cats:
                last_cat = cats[-1]
                if last_cat.startswith('and '):
                    cats[-1] = last_cat[4:]

    for c in cats:
        c = c.strip().rstrip('.')
        if len(c) > 2:
            cat_count[c] += 1

print('Categories found:')
for cat, cnt in cat_count.most_common(15):
    print(f'  {cat}: {cnt}')

top_cat = cat_count.most_common(1)[0]
print(f'\nTop category: {top_cat[0]} ({top_cat[1]} businesses)')

